fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Long {
    val MOD = 1000000007L
    for (query in queries) {
        val li = query[0].toInt()
        val ri = query[1].toInt()
        val ki = query[2].toInt()
        val vi = query[3].toInt()
        var currentIdx = li
        while (currentIdx <= ri) {
            nums[currentIdx] = (nums[currentIdx] * vi) % MOD
            currentIdx += ki
        }
    }
    var xorResult = 0L
    for (num in nums) {
        xorResult ^= num
    }
    return xorResult
}
